describe("drain sink", () => {
  it("should process data correctly when stream has data", (done) => {
    let callCount = 0;
    const source = (abort: any, cb: (end: boolean | Error, data?: any) => void) => {
      if (callCount === 0) {
        callCount++;
        cb(false, "data1");
      } else if (callCount === 1) {
        callCount++;
        cb(false, "data2");
      } else {
        cb(true);
      }
    };

    const sink = drain((data: any) => {
      expect(data).toBeDefined();
      return true;
    }, (err: Error | null) => {
      expect(err).toBeNull();
      done();
    });

    sink(source);
  });
});
